function sliderServices() {
    var swiper = new Swiper('.services .mySwiper', {
        slidesPerView: 'auto',
        spaceBetween: 30,
        speed: 500,
        navigation: {
            nextEl: ".services .swiper-button-next",
            prevEl: ".services .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 16,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 16,
            },
            769: {
                slidesPerView: 2,
                spaceBetween: 16,
            },
            993: {
                slidesPerView: "auto",
                spaceBetween: 30,
            }
        }
    })
}

function sliderPartners() {
    var swiper = new Swiper('.partners .mySwiper', {
        slidesPerView: 4,
        spaceBetween: 30,
        speed: 500,
        grid: {
            rows: 3,
            fill: 'row',
        },
        navigation: {
            nextEl: ".partners .swiper-button-next",
            prevEl: ".partners .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 2,
                spaceBetween: 16,
                grid: {
                    rows: 2,
                },
            },
            451: {
                slidesPerView: 3,
                spaceBetween: 16,
                grid: {
                    rows: 2,
                },
            },
            769: {
                slidesPerView: 4,
                spaceBetween: 16,
                grid: {
                    rows: 3,
                },
            },
            993: {
                slidesPerView: 4,
                spaceBetween: 30,
                grid: {
                    rows: 3,
                },
            }
        }

    })
}

function sliderNews() {
    var swiper = new Swiper('.news .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 30,
        speed: 500,
        navigation: {
            nextEl: ".news .swiper-button-next",
            prevEl: ".news .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 16,
            },
            451: {
                slidesPerView: 1.3,
                spaceBetween: 16,
            },
            769: {
                slidesPerView: 2,
                spaceBetween: 15,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 30,
            }
        }
    })
}

function sliderRisks() {
    var swiper = new Swiper(".risks__sliders .mySwiper", {
        slidesPerView: 1,
        spaceBetween: 30,
        allowTouchMove: false,
    });
    var swiper2 = new Swiper(".risks__sliders .mySwiper2", {
        slidesPerView: 1,
        spaceBetween: 30,
        effect: "fade",
        speed: 500,
        thumbs: {
            swiper: swiper,
        },
        navigation: {
            nextEl: ".swiper-button-next",
            prevEl: ".swiper-button-prev",
        },
    });
}


$(document).ready(function () {
    sliderServices();
    sliderPartners();
    sliderNews();
    sliderRisks();

    // Menu
    if (window.innerWidth > 992) {
        $('.has-dropdown').hover(function () {
        $(this).toggleClass('has-dropdown--active')
        })
    }

    if (window.innerWidth < 992) {
        $('.has-dropdown').click(function () {
        $(this).toggleClass('has-dropdown--active')
        })
    }

    $('.burger').click(function () {
        $(this).toggleClass('burger--active')
        $('.header__list').toggleClass('header__list--active')
    })

    // Accordion
    $(".item-show").click(function() {
        if ($(this).hasClass("item-show--active")) {
            $(this).removeClass("item-show--active");
            $(this).siblings(".item-hidden").slideUp();
        } else {
            $(".item-show").removeClass("item-show--active");
            $(".item-hidden").slideUp();
            $(this).addClass("item-show--active");
            $(this).siblings(".item-hidden").slideDown();
        }
    });

})